[MemoryDiagnoser]
[SimpleJob]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    private const string SampleText =
        "The quick brown fox jumps over the lazy dog and the quick brown fox runs " +
        "around the big beautiful garden where many different animals live together " +
        "in perfect harmony during the warm summer days and cool autumn nights while " +
        "the birds sing their melodious songs from the tall ancient oak trees that " +
        "have stood in this enchanted forest for hundreds of wonderful peaceful years";

    [GlobalSetup]
    public void Setup()
    {
        _analyzer = new TextAnalyzer(SampleText);
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

